+	if err != nil {
+		return err
+	}
+
+	if outfmt.IsJSON(ctx) {
+		return outfmt.WriteJSON(os.Stdout, map[string]any{"space": resp})
+	}
+
+	if resp == nil {
+		u.Out().Printf("space\t%s", displayName)
+		return nil
+	}
+	if resp.Name != "" {
+		u.Out().Printf("resource\t%s", resp.Name)
+	}
+	if resp.DisplayName != "" {
+		u.Out().Printf("name\t%s", resp.DisplayName)
+	}
+	return nil
+}

